-- LIMINARES (cruzado, com periodo) e APOIO (por periodo). Ctrl+A -> Ctrl+Enter.
DROP TABLE IF EXISTS ee_liminar_escola CASCADE;
DROP TABLE IF EXISTS ee_liminar_aluno CASCADE;
DROP TABLE IF EXISTS ee_liminar_unidade CASCADE;
DROP TABLE IF EXISTS ee_apoio CASCADE;
CREATE TABLE ee_apoio (id serial PRIMARY KEY, tipo text, escola text, prof_manha int, prof_tarde int, apoios int);
ALTER TABLE ee_apoio DISABLE ROW LEVEL SECURITY;
CREATE TABLE ee_liminar_aluno (id serial PRIMARY KEY, aluno text, ra text, escola text, turma text, periodo text, deficiencia text, status text);
ALTER TABLE ee_liminar_aluno DISABLE ROW LEVEL SECURITY;
CREATE TABLE ee_liminar_unidade (id serial PRIMARY KEY, escola text, tipo text, alunos int, prof_manha int, prof_tarde int, apoios int, status text);
ALTER TABLE ee_liminar_unidade DISABLE ROW LEVEL SECURITY;

CREATE OR REPLACE FUNCTION ee_apoio() RETURNS json LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $FN$
  SELECT json_build_object(
    'geral',(SELECT json_build_object('escolas',count(*),'prof_manha',coalesce(sum(prof_manha),0),'prof_tarde',coalesce(sum(prof_tarde),0),'professores',coalesce(sum(prof_manha+prof_tarde),0),'apoios',coalesce(sum(apoios),0)) FROM ee_apoio),
    'escolas',coalesce((SELECT json_agg(json_build_array(tipo,escola,prof_manha,prof_tarde,apoios)) FROM (SELECT * FROM ee_apoio ORDER BY tipo,escola) s),'[]'::json)
  );
$FN$;
CREATE OR REPLACE FUNCTION ee_liminar() RETURNS json LANGUAGE sql STABLE SECURITY DEFINER SET search_path=public AS $FN$
  SELECT json_build_object(
    'geral',(SELECT json_build_object('alunos',(SELECT count(*) FROM ee_liminar_aluno),'unidades',(SELECT count(*) FROM ee_liminar_unidade),
       'atendidas',(SELECT count(*) FROM ee_liminar_unidade WHERE status='Atendida'),'pendentes',(SELECT count(*) FROM ee_liminar_unidade WHERE status='Pendência'),
       'fora',(SELECT count(*) FROM ee_liminar_unidade WHERE status='Fora da rede municipal'),'alunos_pend',(SELECT count(*) FROM ee_liminar_aluno WHERE status='Pendência'))),
    'unidades',coalesce((SELECT json_agg(json_build_array(escola,tipo,alunos,prof_manha,prof_tarde,apoios,status)) FROM (SELECT * FROM ee_liminar_unidade ORDER BY status,escola) s),'[]'::json),
    'alunos',coalesce((SELECT json_agg(json_build_array(aluno,ra,escola,turma,periodo,deficiencia,status)) FROM (SELECT * FROM ee_liminar_aluno ORDER BY escola,aluno) s),'[]'::json)
  );
$FN$;
GRANT SELECT ON ee_apoio, ee_liminar_aluno, ee_liminar_unidade TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_apoio() TO anon, authenticated;
GRANT EXECUTE ON FUNCTION ee_liminar() TO anon, authenticated;
